import React, { useContext, useEffect, useState } from "react";
import Preloader from "../../componant/Preloader";
import SupplierContext from "../../context/GetSupplier/SupplierContext";
export default function MyCart(props) {
  const context = useContext(SupplierContext);
  const {
    cartProducts,
    getCartProduct,
    setCartProduct,
    removeFromCart,
    createOrder,
  } = context;
  const [preloader, setPreloader] = useState("");
  useEffect(() => {
    getCartProduct();
  }, []);

  let grand = 0;
  const removeItemFromCart = async (id) => {
    setPreloader("preShow");
    const res = await removeFromCart(id);
    if (res === "Success") {
      props.showAlert("Product has been removed", "success");
    } else {
      props.showAlert("Something Went Wrong", "danger");
    }
    setPreloader("");
  };

  const onchangeQty = (e, id) => {
    const updateCart = cartProducts.map((pro) => {
      return pro._id === id ? { ...pro, qty: e.target.value } : pro;
    });
    setCartProduct(updateCart);
  };

  // place order code is here

  const placeOrder = async () => {
    setPreloader("preShow");
    let myArr = [];
    let total_price = 0;
    for (let i = 0; i < cartProducts.length; i++) {
      const element = cartProducts[i];
      let price = element.price;
      if (element.type === "mpkg") {
        price = element.price * element.product_id.mpkg;
      } else if (element.type === "pkg") {
        price = element.price * element.product_id.pkg;
      }
      if (myArr.length === 0) {
        myArr.push({
          cart_id: element._id,
          catlog_id: element.catlog_id._id,
          c_id:element.catlog_id.c_id,
          catuserid: element.catlog_id.userid,
          product_id: element.product_id._id,
          qty: element.qty,
          type: element.type,
          price: element.price,
          key: element.key,
        });

        const salePrice = element.catlog_id.flattDiscount
          ? price - element.catlog_id.discount
          : (price * (100 - element.catlog_id.discount)) / 100;
        total_price = salePrice * element.qty;
      } else {
        const check = myArr.some(
          (item) => (element.catlog_id.userid === item.catuserid && element.catlog_id.c_id === item.c_id)
        );
        if (check) {
          myArr.push({
            cart_id: element._id,
            catlog_id: element.catlog_id._id,
            c_id:element.catlog_id.c_id,
            catuserid: element.catlog_id.userid,
            product_id: element.product_id._id,
            qty: element.qty,
            type: element.type,
            price: element.price,
            key: element.key,
          });

          const salePrice = element.catlog_id.flattDiscount
            ? price - element.catlog_id.discount
            : (price * (100 - element.catlog_id.discount)) / 100;
          total_price = total_price + salePrice * element.qty;
        }
      }
    }

    const orderarr = {
      supplier_id: myArr[0].catuserid,
      supplier_c_id: myArr[0].c_id,
      order_list: myArr,
      total_price,
      create_by: "user",
    };
    console.log(myArr);
    const response = await createOrder(orderarr);
    if (response.status === "Success") {
      for (let i = 0; i < myArr.length; i++) {
        const element = myArr[i];
        await removeFromCart(element.cart_id);
      }
      props.showAlert("Order Has Been Created", "success");
      setPreloader("");
      getCartProduct();
    } else {
      props.showAlert("Something Went Wrong", "danger");
      setPreloader("");
    }

    // console.log(myArr);
  };

  return (
    <>
      <Preloader show={preloader} />
      <div className="content-wrapper">
        <div className="container-xxl flex-grow-1 container-p-y">
          <div className="fixed-button">
            <div
              className="btn btn-sm fixed_button btn-outline-primary"
              onClick={() => {
                placeOrder();
              }}
            >
              Place order
            </div>
          </div>

          <div className="row mb-4">
            <div className="col-lg-12 ">
              <span className="supplier_name">My Cart</span>
              <br />
              <small className="p-0  ">
                You've selected the products from {"three "}different suppliers
                so your {"three "}
                different orders will be created simultaneously.
              </small>
            </div>
          </div>

          <div className="row">
            <div className="col-lg-12 mb-4 ">
              <div className="card">
                <h5 className="card-header">
                  <div className="row">
                    <div className="col-lg-6 font-bold">
                      <ul className="slider_button slider-white plain-orange">
                        <li className="slider-active">
                          Total Products ({cartProducts.length}){" "}
                        </li>
                      </ul>
                    </div>
                  </div>
                </h5>

                <div className="table-responsive text-nowrap mb-1">
                  <table className="table table-hover">
                    <thead className="order_history_header">
                      <tr>
                        <th>S No.</th>
                        <th>Image</th>
                        <th>Product Name</th>
                        <th>Price</th>
                        <th>Qty</th>
                        <th>Total Amount</th>
                        {/* <th className="action">Action</th> */}
                      </tr>
                    </thead>
                    <tbody className="table-border-bottom-0 order_history_body cart_table">
                      {cartProducts.map((cart, index) => {
                        let price = cart.price;
                        if (cart.type === "mpkg") {
                          price = cart.price * cart.product_id.mpkg;
                        } else if (cart.type === "pkg") {
                          price = cart.price * cart.product_id.pkg;
                        }
                        let salePrice = cart.price;
                        salePrice = cart.catlog_id.flattDiscount
                          ? price - cart.catlog_id.discount
                          : (price * (100 - cart.catlog_id.discount)) / 100;

                        const total = salePrice * cart.qty;
                        grand = grand + total;

                        return (
                          <tr key={index}>
                            <td>{index + 1}</td>
                            <td>
                              <img
                                src={cart.product_id.p_gallery_image[0].link}
                                alt="image"
                                className="img-fluid"
                                width={50}
                              />
                            </td>
                            <td>
                              {cart.product_id.p_name} ({" "}
                              {cart.product_id.p_price.map((p) => {
                                return p.value === cart.price ? p.name : "";
                              })}{" "}
                              )
                              <br />
                              <small>
                                <i
                                  className="bx bx-trash"
                                  onClick={() => {
                                    removeItemFromCart(cart._id);
                                  }}
                                ></i>
                              </small>
                            </td>
                            <td>
                              {" "}
                              ₹ {salePrice} (
                              <small>
                                {price}/{cart.key}
                              </small>
                              )
                            </td>
                            <td className="cartqty">
                              <input
                                type="number"
                                className="form-control"
                                defaultValue={cart.qty}
                                onChange={(e) => {
                                  onchangeQty(e, cart._id);
                                }}
                              />
                            </td>
                            <td className="cartTotal">₹ {total}</td>
                            {/* <td className="action">
                            <span className="badge badge-secondary my-delete">
                              <i className="bx bx-trash-alt "></i>
                            </span>
                          </td> */}
                          </tr>
                        );
                      })}
                    </tbody>
                    <tfoot className="cart-footer">
                      <tr>
                        <td colSpan={3}></td>
                        <td>Grand Total</td>
                        <td className="cart_total">₹ {grand}</td>
                        <td></td>
                      </tr>
                    </tfoot>
                  </table>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
}
