import React, { useContext, useEffect, useState } from "react";
import Alert from "../componant/Alert";
import Preloader from "../componant/Preloader";
import CatContext from "../context/Category/catContext";

export const Category = () => {
  const mycontext = useContext(CatContext);
  const {
    category,
    getAllCategory,
    addCategory,
    addSubCategory,
    deleteCategoryapi,
    deleteSubCategoryapi,
  } = mycontext;
  
  const [preloader, setPreloader] = useState("");

  useEffect(() => {
    getAllCategory();
  }, []);

  // add Category
  const [newCategory, setCategory] = useState({
    cat_name: "",
    c_id: localStorage.getItem("com_id"),
  });

  const handleClick = async (e) => {
    e.preventDefault();
    setPreloader("preShow");
    const restr = await addCategory(newCategory);
    setAddCategoryModal(!addCategoryModal);
    setPreloader("");
  };

  const onChange = (e) => {
    console.log(e.target.name);
    setCategory({ ...newCategory, [e.target.name]: e.target.value });
  };
  // add Category

  // add sub Category
  const [id, setid] = useState("");
  const [newSubcat, setSub] = useState({
    name: "",
  });

  const subHandleClick = async (e) => {
    e.preventDefault();
    setPreloader("preShow");
    const restr = await addSubCategory(newSubcat, id);
    if (restr.status === "Sucess") {
      openSubData();
      showAlert("Created", "success");
    } else {
      showAlert(restr.msg, "danger");
    }
    setPreloader("");
    //console.log(restr);
  };

  const srtId = (e) => {
    setid(e.target.value);
  };

  const onsubhange = (e) => {
    setSub({ ...newSubcat, [e.target.name]: e.target.value });
  };
  // add sub Category

  // delete sub category

  const deleteSubCategory = async (s_id, id) => {
    setPreloader("preShow");
    const res = await deleteSubCategoryapi([{ id: s_id }], id);

    if (res.status === "Failed") {
      showAlert(res.msg, "danger");
    } else {
      showAlert(res.msg, "success");
    }
    setPreloader("");
  };

  // delete whole  category
  const deleteCategory = async (id) => {
    setPreloader("preShow");
    const cat = await deleteCategoryapi(id);
    setPreloader("");
  };

  // showaler

  const [alert, setAlert] = useState(null);
  const showAlert = (message, type) => {
    setAlert({
      msg: message,
      type: type,
      active: "alert-active",
    });
    setTimeout(() => {
      setAlert(null);
    }, 2000);
  };

  const style = {
    background: "#00000080",
    display: "block",
  };
  const [addCategoryModal, setAddCategoryModal] = useState(false);
  const [addsubCategoryModal, setAddsubCategoryModal] = useState(false);
  const openData = () => {
    setAddCategoryModal(!addCategoryModal);
  };
  const openSubData = () => {
    setAddsubCategoryModal(!addsubCategoryModal);
  };

  console.log(category);
  return (
    <>
      <Preloader show={preloader} />
      {alert && <Alert alert={alert} />}
      {addCategoryModal && (
        <div className="modal reviewModal" style={style}>
          <div className="modal-dialog" style={{ width: "40%" }}>
            <div className="modal-content">
              <div className="modal-header">
                <h5 className="modal-title" id="exampleModalLabel">
                  Add Category
                </h5>
                <button
                  type="button"
                  className="btn-close"
                  data-bs-dismiss="modal"
                  aria-label="Close"
                  onClick={openData}
                ></button>
              </div>
              <div className="modal-body">
                <form
                  id="formAccountSettings"
                  method="POST"
                  onSubmit={handleClick}
                >
                  <div className="row">
                    {/* category add section */}
                    <div className="col-md-12  my-1">
                      <form method="post">
                        <div className="form-group">
                          <input
                            type="text"
                            className="form-control    m-0"
                            name="cat_name"
                            id=""
                            aria-describedby="helpId"
                            placeholder="Category Name"
                            onChange={onChange}
                          />
                        </div>
                      </form>
                    </div>
                    {/* category add section end */}
                  </div>
                  <div className="mt-3">
                    <button
                      type="reset"
                      className="btn btn-outline-primary me-2 my-btn"
                    >
                      Cancel
                    </button>
                    <button
                      type="submit"
                      className="btn orange-btn btn-primary me-2"
                      onClick={handleClick}
                    >
                      Add
                    </button>
                  </div>
                </form>
              </div>
            </div>
          </div>
        </div>
      )}

      {addsubCategoryModal && (
        <div className="modal reviewModal" style={style}>
          <div className="modal-dialog" style={{ width: "40%" }}>
            <div className="modal-content">
              <div className="modal-header">
                <h5 className="modal-title" id="exampleModalLabel">
                  Add Sub Category
                </h5>
                <button
                  type="button"
                  className="btn-close"
                  data-bs-dismiss="modal"
                  aria-label="Close"
                  onClick={openSubData}
                ></button>
              </div>
              <div className="modal-body">
                <form
                  id="formAccountSettings"
                  method="POST"
                  onSubmit={handleClick}
                >
                  <div className="row">
                    <div className="col-md-12 my-1">
                      <form method="post">
                        <div className="form-group">
                          <select
                            className="form-control    m-0 mb-3"
                            name="id"
                            id=""
                            onChange={srtId}
                          >
                            <option>Choose Primary Category</option>
                            {category.map((c, i) => {
                              return (
                                <option key={i} value={c._id}>
                                  {c.cat_name}
                                </option>
                              );
                            })}
                          </select>
                        </div>

                        <div className="form-group">
                          <input
                            type="text"
                            className="form-control    m-0"
                            name="name"
                            id=""
                            aria-describedby="helpId"
                            placeholder="Sub Category Name"
                            onChange={onsubhange}
                          />
                        </div>
                      </form>
                    </div>
                  </div>
                  <div className="mt-2">
                    <button
                      type="reset"
                      className="btn btn-outline-primary me-2 my-btn"
                    >
                      Cancel
                    </button>
                    <button
                      type="submit"
                      className="btn orange-btn btn-primary me-2"
                      onClick={subHandleClick}
                    >
                      Add
                    </button>
                  </div>
                </form>

                {/* <p className="instruction_para">
    [Customer Name] will recieve an invitation from your Company,
    when he will accept your invitation your customer will be
    added.
  </p> */}
              </div>
              {/* <div className="modal-footer">
  <button
    type="button"
    className="btn btn-primary orange-btn me-2 mb-2"
  >
    Create Now
  </button>
</div> */}
            </div>
          </div>
        </div>
      )}

      <div className="content-wrapper">
        <div className="container-xxl flex-grow-1 container-p-y">
          <div className="fixed-button">
            <div
              className="btn btn-sm fixed_button btn-outline-primary"
              onClick={openData}
            >
              + Add Category
            </div>
            <div
              className="btn btn-sm  bulkuplod btn-outline-primary"
              onClick={openSubData}
            >
              + Add Sub Category
            </div>
          </div>
          <div className="row">
            <h4 className="card-header c_heading">
              <span className="headingcontent">
                My Categories ({category.length})
              </span>

              <div className="heading_buttons">
                <input
                  className="form-control  search  mb-4"
                  placeholder="Search category..."
                />
              </div>
            </h4>

            <div className="col-lg-12 mb-4 ">
              <div class="card">
                <h5 class="card-header">
                  <div className="row">
                    <div className="col-lg-6 font-bold">
                      <ul className="slider_button slider-white plain-orange">
                        <li className="slider-active">Categories</li>
                      </ul>
                    </div>
                    <div className="col-lg-6 text-right">
                      <input
                        type="text"
                        className="form-control search"
                        placeholder="Search Category..."
                      />
                    </div>
                  </div>
                </h5>

                <div class="table-responsive text-nowrap mb-1">
                  <table class="table table-hover">
                    <thead className="order_history_header">
                      <tr>
                        <th>Primary Category</th>
                        <th>Sub Category</th>
                        <th className="action">Action</th>
                      </tr>
                    </thead>
                    <tbody class="table-border-bottom-0 order_history_body">
                      {category.map((c, i) => {
                        return (
                          <>
                            <tr>
                              <td>{c.cat_name}</td>
                              <td>
                                {c.sub_items.map((s, j) => {
                                  return (
                                    <>
                                      <div className="dropdown subcategory">
                                        <button
                                          type="button"
                                          className="btn p-0 dropdown-toggle hide-arrow"
                                          data-bs-toggle="dropdown"
                                        >
                                          {s.name}
                                          <i className="bx bx-dots-vertical-rounded"></i>
                                        </button>
                                        <div className="dropdown-menu">
                                          <p
                                            className="dropdown-item"
                                            onClick={() => {
                                              deleteSubCategory(s._id, c._id);
                                            }}
                                          >
                                            <i className="bx bx-edit me-1"></i>
                                            Edit
                                          </p>
                                          <p
                                            className="dropdown-item"
                                            onClick={() => {
                                              deleteSubCategory(s._id, c._id);
                                            }}
                                          >
                                            <i className="bx bx-trash me-1"></i>
                                            Delete
                                          </p>
                                        </div>
                                      </div>
                                    </>
                                  );
                                })}
                              </td>
                              <td className="action">
                                <div className="dropdown">
                                  <button
                                    type="button"
                                    className="btn p-0 dropdown-toggle hide-arrow"
                                    data-bs-toggle="dropdown"
                                  >
                                    <i className="bx bx-dots-vertical-rounded"></i>
                                  </button>
                                  <div className="dropdown-menu">
                                    <p className="dropdown-item">
                                      <i className="bx bx-edit-alt me-1"></i>{" "}
                                      Edit
                                    </p>

                                    <p
                                      className="dropdown-item"
                                      onClick={() => {
                                        deleteCategory(c._id);
                                      }}
                                    >
                                      <i className="bx bx-trash me-1"></i>{" "}
                                      Delete
                                    </p>
                                  </div>
                                </div>
                              </td>
                            </tr>
                          </>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};
