import React, { useState } from "react";
import CusContext from "./CustomerContext";

const CustomerState = (props) => {
  const getAllCustomer = async () => {
    // console.log(localStorage.getItem("token"));
    const requestOptions = {
      method: "GET",
      headers: {
        "Content-Type": "application/json",
        "auth-token": localStorage.getItem("token"),
      },
    };
    const response = await fetch(
      "http://localhost:4000/api/customer/getCustomers",
      requestOptions
    );
    const datares = await response.json();

    let datasets = await Promise.all(
      datares.data.map(async (cus) => {
        const order = await getAllOrder(cus.customer_id._id);
        return { ...cus, order };
      })
    );

    setCustomerData(datasets);
  };

  const getAllOrder = async (userid) => {
    const requestOptions = {
      method: "GET",
      headers: {
        "Content-Type": "application/json",
        "auth-token": localStorage.getItem("token"),
      },
    };
    const response = await fetch(
      `http://localhost:4000/api/order/getOrderByUser/${userid}`,
      requestOptions
    );
    const datares = await response.json();
    let totalamt = 0;
    for (let i = 0; i < datares.data.length; i++) {
      const element = datares.data[i];
      totalamt = totalamt + parseInt(element.total_price, 10);
    }
    return totalamt;
  };

  const customers_data = [
    {
      customer_id: {
        _id: "",
        userid: "",
        phone: "",
        name: "",
        email: "",
        address: "",
        cus_image: "",
        com_name: "",
        gst_no: "",
        bus_type: "",
        __v: 0,
      },
    },
  ];
  const [myCustomer, setCustomerData] = useState(customers_data);

  const addCustomer = async (data) => {
    try {
      //const bodydata = com_name;
      console.log(data);
      const requestOptions = {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          "auth-token": localStorage.getItem("token"),
        },
        body: JSON.stringify(data),
      };
      const response = await fetch(
        "http://localhost:4000/api/auth/addCustomer",
        requestOptions
      );
      const datares = await response.json();

      if (datares.status === "Failed") {
      } else {
        const comp = datares.data;
        setCustomerData(myCustomer.concat({ customer_id: comp }));
        console.log(comp);
      }
      return datares;
    } catch (e) {
      console.log(e.message);
    }
  };

  const deleteCustomer = () => {};

  return (
    <CusContext.Provider
      value={{
        myCustomer,
        deleteCustomer,
        getAllCustomer,
        addCustomer,
        setCustomerData,
        getAllOrder,
      }}
    >
      {props.children}
    </CusContext.Provider>
  );
};

export default CustomerState;
