import React, { useState, useContext, useEffect } from "react";

import { Link } from "react-router-dom";
import MyButton from "../componant/MyButton";
import CusContext from "../context/Customer/CustomerContext";

export const Customer = (props) => {
  // data from custormercontext
  const token = localStorage.getItem("token");
// console.log(token);
  const showalert = (message, type) => {
    props.showAlert(message, type);
  };

  const context = useContext(CusContext);
  const { myCustomer, getAllCustomer, addCustomer, getAllOrder } = context;

  const [newCustomer, setCustomer] = useState({
    phone: "",
    fullname: "",
    password: "",
    type: "user",
  });

  useEffect(() => {
    getAllCustomer();
  }, []);

  const updateOutStanding = async ()=>{
    const newdata = await myCustomer.map(async(cus) => {      
      const order = await getAllOrder(cus.customer_id._id);
      return { ...cus, order };      
      
    });
    console.log(newdata);
  }


  // console.log(myCustomer);
  const uploadCustomer = async (e) => {
    e.preventDefault();
    console.log("clicked");
    const restr = await addCustomer(newCustomer);
    console.log(restr);
    if (restr.status === "Failed") {
      showalert(restr.msg, "danger");
    } else {
      showalert("Customer has been added", "success");
      openData();
    }
  };

  const inputFuction = (e) => {
    setCustomer({ ...newCustomer, [e.target.name]: e.target.value });
  };

  const [modal, setModal] = useState(false);
  const [uploadModal, setUploadmodeal] = useState(false);
  const [confirmModal, setconfirmModal] = useState(false);

  const style = {
    background: "#00000080",
    display: "block",
  };

  const openData = () => {
    setModal(!modal);
  };

  const openUploadModal = () => {
    setUploadmodeal(!uploadModal);
  };

  const openconfirmModal = () => {
    setconfirmModal(!confirmModal);
  };

  return (
    <>
      {/* modal add customer */}

      {modal && (
        <div className="modal reviewModal" style={style}>
          <div className="modal-dialog">
            <div className="modal-content">
              <div className="modal-header">
                <h5 className="modal-title" id="exampleModalLabel">
                  Create Customer
                </h5>
                <button
                  type="button"
                  className="btn-close"
                  data-bs-dismiss="modal"
                  aria-label="Close"
                  onClick={openData}
                ></button>
              </div>
              <div className="modal-body">
                <form method="POST">
                  <div className="mb-3">
                    <label htmlFor="fullname" className="col-form-label">
                      Customer Name :
                    </label>
                    <input
                      type="text"
                      className="form-control"
                      name="fullname"
                      id="fullname"
                      placeholder="Customer Name"
                      onChange={inputFuction}
                    />
                  </div>
                  <div className="mb-3">
                    <label htmlFor="phone" className="col-form-label">
                      Customer Phone No.
                    </label>
                    <input
                      type="text"
                      className="form-control"
                      id="phone"
                      name="phone"
                      placeholder="Customer Phone No."
                      onChange={inputFuction}
                    />
                  </div>

                  <div className="mb-3">
                    <label htmlFor="password" className="col-form-label">
                      Password
                    </label>
                    <input
                      type="text"
                      className="form-control"
                      id="password"
                      name="password"
                      placeholder="Customer Password"
                      onChange={inputFuction}
                    />
                  </div>
                </form>

                <p className="instruction_para">
                  [Customer Name] will recieve an invitation from your Company,
                  when he will accept your invitation your customer will be
                  added.
                </p>
              </div>
              <div className="modal-footer">
                <button
                  type="submit"
                  className="btn btn-primary orange-btn me-2 mb-2"
                  onClick={uploadCustomer}
                >
                  Create Now
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {uploadModal && (
        <div className="modal reviewModal" style={style}>
          <div className="modal-dialog">
            <div className="modal-content">
              <div className="modal-header">
                <h5 className="modal-title" id="exampleModalLabel">
                  Bulk Upload Customers From Excel
                </h5>
                <button
                  type="button"
                  className="btn-close"
                  data-bs-dismiss="modal"
                  aria-label="Close"
                  onClick={openUploadModal}
                ></button>
              </div>
              <div className="modal-body">
                <form>
                  <div className="mb-3">
                    <label htmlFor="recipient-name" className="col-form-label">
                      Choose File :
                    </label>
                    <input
                      type="file"
                      className="form-control"
                      id="review_name"
                      placeholder="Customer Name"
                    />
                  </div>
                </form>

                <p className="instruction_para">
                  Upload the Excelsheet of customer's name and phone numbers in
                  the following format.
                </p>
                <Link>
                  <u>Download Demo Sheet.</u>
                </Link>
              </div>
              <div className="modal-footer">
                <button
                  type="button"
                  className="btn btn-primary orange-btn me-2 mb-2"
                >
                  Upload
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {confirmModal && (
        <div className="modal reviewModal" style={style}>
          <div className="modal-dialog">
            <div className="modal-content">
              <div className="modal-header">
                <h5 className="modal-title" id="exampleModalLabel">
                  Cancel invitation
                </h5>
                <button
                  type="button"
                  className="btn-close"
                  data-bs-dismiss="modal"
                  aria-label="Close"
                  onClick={openconfirmModal}
                ></button>
              </div>
              <div className="modal-body">
                <p className="instruction_para">
                  Are you sure, you want to cancel your invitation.
                </p>
              </div>
              <div className="modal-footer">
                <button
                  type="button"
                  className="btn btn-primary orange-btn  me-2 mb-2"
                >
                  Yes
                </button>
                <button
                  type="button"
                  className="btn btn-primary my_cancel_button me-2 mb-2"
                >
                  No
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* modal add customer */}

      <div className="content-wrapper">
        <div className="container-xxl flex-grow-1 container-p-y">
          <div className="fixed-button">
            <div
              className="btn btn-sm fixed_button btn-outline-primary"
              onClick={openData}
            >
              + Add Customer
            </div>

            <div
              className="btn btn-sm  bulkuplod btn-outline-primary"
              onClick={openUploadModal}
            >
              + Upload From Excel
            </div>
          </div>
          <div className="row">
            <h4 className="card-header c_heading">
              <span className="headingcontent">
                My Customers ({myCustomer.length})
              </span>

              <div className="heading_buttons"></div>
            </h4>
            <input
              className="form-control search mb-4"
              placeholder="Search Customers..."
            />
            {myCustomer.length === 0 && "No Customer Found"}

            <div className="col-lg-12 mb-4 ">
              <div className="card">
                <h5 className="card-header">
                  <div className="row">
                    <div className="col-lg-6 text-right">
                      <input
                        type="text"
                        className="form-control search"
                        placeholder="Search by Staff Name, Roles, Phone No., Staff Id , etc..."
                      />
                    </div>

                    <div className="col-lg-6 font-bold">
                      <MyButton />
                    </div>
                  </div>
                </h5>

                <div className="table-responsive text-nowrap mb-1">
                  <table className="table table-hover">
                    <thead className="order_history_header">
                      <tr>
                        <th>Profile Pic.</th>
                        <th>Name</th>
                        <th>Phone</th>
                        <th>Address</th>
                        <th>Out Standing Balance</th>
                        <th className="action">Action</th>
                      </tr>
                    </thead>
                    <tbody className="table-border-bottom-0 order_history_body">
                      {myCustomer.length === 0 && "No Customer Found"}
                      {myCustomer.map((sup) => {
                        
                        
                        return (
                          <tr key={sup._id}>
                            <td>
                              <img
                                src="../assets/img/avatars/5.png"
                                alt="Avatar"
                                width="60"
                                height="60"
                                className="rounded-circle customer_image my-auto"
                              />
                            </td>
                            <td>{sup.customer_id.fullname}</td>
                            <td>{sup.customer_id.phone}</td>
                            <td>{sup.customer_id.address}</td>
                            <td>
                              <span
                                className="badge rounded-pill bg-label-success w-100"
                                style={{ fontSize: "1.4em" }}
                              >
                                {sup.order}
                              </span>
                            </td>
                            <td>Action</td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};
