import React, { useState, useEffect, useContext } from "react";
import { Link } from "react-router-dom";
import MyButton from "../componant/MyButton";
import productContext from "../context/Product/productContext";
import Noticontext from "../context/notification/NotifContext";
import "../css/slider.css";
import orderconfirm from "../svgicon/confirmed.svg"
require("dotenv").config();
export default function Order(props) {
  const host = process.env.REACT_APP_URL;
  const [myOrders, setMyOrders] = useState([]);

  const notiContext = useContext(Noticontext);

  const { notification, getAllNotificaiton, pushNotification } = notiContext;

  const getAllOrders = async () => {
    const requestOptions = {
      method: "GET",
      headers: {
        "Content-Type": "application/json",
        "auth-token": localStorage.getItem("token"),
      },
    };
    const response = await fetch(
      `${host}/api/order/getOrdersBySupplier/${localStorage.getItem("com_id")}`,
      requestOptions
    );
    const datares = await response.json();
    setMyOrders(datares.data);
  };

  useEffect(() => {
    if (localStorage.getItem("token") !== null) {
      getAllOrders();
      getAllProduct();
    }
  }, []);

  // product section
  const productcontext = useContext(productContext);
  const { product, getAllProduct } = productcontext;

  const GetproductDetail = (id) => {
    const matchProduct = product.filter((pro) => {
      return pro._id === id.product_id;
    });
    return matchProduct;
  };

  const changeStatus = async (orderid, statusType) => {
    const requestOptions = {
      method: "PUT",
      headers: {
        "Content-Type": "application/json",
        "auth-token": localStorage.getItem("token"),
      },
    };
    const response = await fetch(
      `${host}/api/order/changeOrderStatus/${orderid}/${statusType}`,
      requestOptions
    );
    const datares = await response.json();
    if (datares.status === "Success") {
      props.showAlert(datares.msg, "success");
      pushNotification(
        datares.data.userid,
        "order",
        "Change Order Status",
        datares.msg
      );
      getAllOrders();
    } else {
      props.showAlert(datares.msg, "danger");
    }
  };

  return (
    <>
    
      <div className="content-wrapper">
        <div className="container-xxl flex-grow-1 container-p-y">
          <div className="row">
            <h4 className="card-header c_heading">
              <span className="headingcontent">
                My Orders ({myOrders.length})
              </span>

              <div className="heading_buttons">
                <MyButton />
              </div>
            </h4>

            <div className="col-lg-12 mb-4 ">
              <div className="card">
                <h5 className="card-header">
                  <div className="row align-items-center">
                    <div className="col-lg-4 text-right">
                      <input
                        type="text"
                        className="form-control search"
                        placeholder="Search by Product Name, sku, Status, etc..."
                      />
                    </div>

                    <div className="col-lg-6 font-bold text-right"></div>
                  </div>
                </h5>

                <div className="table-responsive text-nowrap mb-1">
                  <table className="table table-hover">
                    <thead className="order_history_header">
                      <tr>
                        <th>Order ID</th>
                        <th>Date</th>
                        <th>Customer Name</th>
                        <th>Items</th>
                        <th>Order Value</th>
                        <th>Create By</th>
                        <th>Status</th>
                      </tr>
                    </thead>
                    <tbody className="table-border-bottom-0 order_history_body">
                      {myOrders.map((or) => {
                        const date = or.createdAt.split("T");
                        const totalOrder = Number(
                          parseFloat(or.total_price).toFixed(0)
                        );
                        return (
                          <tr>
                            <td>
                              <Link
                                key={or._id}                                
                                to={`/ordersDetails/${or.order_id}`}
                              >
                                #{or.order_id}
                              </Link>
                            </td>
                            <td>
                              {date[0]}
                              <br />
                              <small>{date[1]}</small>
                            </td>
                            <td>
                              <span className="unitSpan">Name - </span>
                              {or.userid.fullname}
                              <br />
                              <span className="unitSpan">Phone - </span>
                              {or.userid.phone}
                            </td>
                            <td>
                              {or.order_list.length}
                              {/* <ul>
                                {or.order_list.map((pro) => {
                                  let price = pro.price;
                                  let unitType = pro.product_id.unit_name;
                                  if (pro.type === "mpkg") {
                                    price = pro.price * pro.product_id.mpkg;
                                    unitType = pro.product_id.mpkg_unit;
                                  } else if (pro.type === "pkg") {
                                    price = pro.price * pro.product_id.pkg;
                                    unitType = pro.product_id.pkg_unit;
                                  } else {
                                    price = pro.price;
                                  }
                                  let salePrice = pro.price * pro.qty;
                                  salePrice = pro.catlog_id.flattDiscount
                                    ? price - pro.catlog_id.discount
                                    : (price * (100 - pro.catlog_id.discount)) /
                                      100;

                                  const total = Number(
                                    (salePrice * pro.qty).toFixed(2)
                                  );

                                  return (
                                    <li key={pro._id}>
                                      <span className="unitSpan">
                                        {pro.product_id.p_name} (
                                        {pro.product_id.p_price.map((p) => {
                                          return p.value === pro.price
                                            ? p.name
                                            : "";
                                        })}{" "}
                                        ) (QTY -{pro.qty})
                                      </span>
                                      <br />
                                      <span className="unitSpan">
                                        Price ({unitType}) - ₹ {salePrice}
                                      </span>
                                      <br />
                                      <span className="unitSpan">
                                        <b>Total - ₹ {total}</b>
                                      </span>
                                    </li>
                                  );
                                })}
                              </ul> */}
                            </td>
                            <td>₹ {totalOrder}</td>
                            <td>{or.create_by}</td>
                            <td>
                              {or.order_status === "pending" ? (
                                <>
                                  <ul className="acceptOrder">
                                    <li
                                      className=" btn orange-btn"
                                      onClick={() => {
                                        changeStatus(or._id, "accept");
                                      }}
                                    >
                                      Accept
                                    </li>
                                    <li
                                      className=" btn"
                                      onClick={() => {
                                        changeStatus(or._id, "reject");
                                      }}
                                    >
                                      Reject
                                    </li>
                                  </ul>
                                </>
                              ) : or.order_status === "reject" ? (
                                <>
                                  <ul className="acceptOrder">
                                    <li className=" btn">Rejected</li>
                                  </ul>
                                </>
                              ) : (
                                <div class="form-group">
                                  <select class="form-control" name="" id="">
                                    <option>Dispatched</option>
                                    <option>Delivered</option>
                                  </select>
                                </div>
                              )}
                            </td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
            {/* table layout */}
          </div>
        </div>
      </div>
    </>
  );
}
